import Vue from 'vue'
import VueRouter from 'vue-router'
// import Vote21 from '../views/Vote21.vue'

// Containers
const DefaultContainer = () => import('@/containers/DefaultContainer')

Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    name: 'Home',
    // 브라우저 언어가 한국어면 한글 페이지, 그 외에는 영문 페이지로 보낸다.
    redirect: () => {
      const langs = (typeof navigator !== 'undefined')
        ? (navigator.languages || [navigator.language || navigator.userLanguage || ''])
        : ['']
      const isKorean = langs.some(l => String(l).toLowerCase().startsWith('ko'))
      return isKorean ? '/familyline' : '/familyline/en'
    },
  },
  {
    path: '/calendar',
    name: 'Calendar',
    redirect: '/calendar',
    component: DefaultContainer,
    children: [
      {
        path: '/',
        name: 'Calendar Home',
        component: () => import('@/views/calendar/Index')
      },
      {
        path: '/monthly',
        name: 'Monthly Calendar',
        component: () => import('@/views/calendar/Monthly')
      },
    ]
  },
  {
    path: '/settings',
    name: 'settings',
    redirect: '/settings',
    component: DefaultContainer,
    children: [
      {
        path: '/',
        name: 'Settings Home',
        component: () => import('@/views/settings/Index')
      },
      {
        path: '/settings/account',
        name: 'Account Settings',
        component: () => import('@/views/settings/Account')
      },
    ]
  },
  {
    path: '/learning',
    name: 'Learning & Study',
    // component: Vote21
    component: () => import('@/views/learning/Learning')
  },
  {
    path: '/learning/vote21',
    name: 'Vote 21',
    component: () => import('@/views/learning/vote21/Vote21')
  },
  {
    path: '/learning/vote21/map',
    name: 'D3.js on Vue.js(Vote21)',
    component: () => import('@/views/learning/vote21/Map')
  },
  {
    path: '/learning/vote22',
    name: 'Vote 22',
    component: () => import('@/views/learning/vote22/Vote22')
  },
  {
    path: '/learning/vote22/map',
    name: 'D3.js on Vue.js(Vote22)',
    component: () => import('@/views/learning/vote22/Map')
  },
  {
    path: '/learning/dynamic-components',
    name: 'Dynamic Components',
    component: () => import('@/views/learning/dynamic-components/Index')
  },
  {
    path: '/familyline',
    name: 'Family Line',
    component: () => import('@/views/familyline/FamilyLine'),
    props: { lang: 'ko' }
  },
  {
    path: '/familyline/en',
    name: 'Family Line (EN)',
    component: () => import('@/views/familyline/FamilyLine'),
    props: { lang: 'en' }
  }
]

const router = new VueRouter({
  // mode: 'history',
  base: process.env.BASE_URL,
  routes
})

export default router
